import{c as e,Q as n,j as r,m as a}from"./chunks/framework.BPKcPtvA.js";const y=JSON.parse('{"title":"Roles & Permissions","description":"","frontmatter":{},"headers":[],"relativePath":"guide/concepts/roles-and-permissions.md","filePath":"guide/concepts/roles-and-permissions.md","lastUpdated":1778912818000}'),s={name:"guide/concepts/roles-and-permissions.md"};function d(i,t,o,l,c,g){return n(),r("div",null,[...t[0]||(t[0]=[a('<h1 id="roles-permissions" tabindex="-1">Roles &amp; Permissions <a class="header-anchor" href="#roles-permissions" aria-label="Permalink to &quot;Roles &amp; Permissions&quot;">​</a></h1><p>Three role systems coexist in the Console, each governing a different layer of the platform:</p><ol><li><strong>Internal roles</strong> — what an Exto operator can do across the platform.</li><li><strong>Portal roles</strong> — what a customer&#39;s users can do inside their own customer portal.</li><li><strong>Tenant roles</strong> — what a user can do <em>inside</em> a specific tenant after they have been provisioned into it.</li></ol><p>The three systems are intentionally separate. An internal operator never holds a portal role; a customer admin never holds an internal role; tenant roles are assigned on top of either, per tenant.</p><p>In the matrices below:</p><ul><li><strong>Y</strong> — full access (read + write).</li><li><strong>R</strong> — read-only.</li><li><strong>—</strong> — no access.</li></ul><p>A user can hold more than one internal role. When that happens, permission checks union all of their roles — Console grants access if <strong>any</strong> of the roles allows it.</p><hr><h2 id="internal-roles" tabindex="-1">Internal roles <a class="header-anchor" href="#internal-roles" aria-label="Permalink to &quot;Internal roles&quot;">​</a></h2><p>Internal roles control what an Exto operator can do across the platform. A user can hold one or more roles.</p><table tabindex="0"><thead><tr><th>Role</th><th>Code</th><th>Description</th></tr></thead><tbody><tr><td><strong>Platform Admin</strong></td><td><code>platform_admin</code></td><td>Full access. Manages instances, plans, internal users, system pages, and platform configuration.</td></tr><tr><td><strong>Infra Ops</strong></td><td><code>infra_ops</code></td><td>Operates the fleet — instances, releases, migrations, environment variables, system workers, discrepancies.</td></tr><tr><td><strong>Finance Admin</strong></td><td><code>finance_admin</code></td><td>Finance-only — billing settings, invoices, payments, plans, meters, usage aggregates, custom plans, credits.</td></tr><tr><td><strong>Compliance Admin</strong></td><td><code>compliance_admin</code></td><td>Audit-focused, read-only. Sees system workers, discrepancies, audit log, email logs. No finance access. Receives discrepancy alerts.</td></tr><tr><td><strong>Reader</strong></td><td><code>reader</code></td><td>View-only across the platform (instances, customers, tenants, users, releases, migrations, system pages). Excludes finance.</td></tr><tr><td><strong>Account Manager</strong></td><td><code>account_manager</code></td><td>Manages a defined set of customers — onboarding, plan changes, billing, invitations. Restricted to their <strong>customer scope</strong>.</td></tr><tr><td><strong>QA Admin</strong></td><td><code>qa_admin</code></td><td>Operates against a defined set of customers <em>and</em> instances — typically for QA cycles or validation against non-prod environments. Restricted to both <strong>customer scope</strong> and <strong>instance scope</strong>.</td></tr></tbody></table><p>When you create an internal user with the Account Manager or QA Admin role, a <strong>scope picker</strong> appears so you can grant the customers (and, for QA Admin, the instances) they may operate on. Empty scope = no access; you must grant at least one entry. Scopes can be modified at any time on the user&#39;s detail page.</p><h3 id="internal-permission-matrix" tabindex="-1">Internal permission matrix <a class="header-anchor" href="#internal-permission-matrix" aria-label="Permalink to &quot;Internal permission matrix&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Capability</th><th style="text-align:center;">Platform Admin</th><th style="text-align:center;">Infra Ops</th><th style="text-align:center;">Finance Admin</th><th style="text-align:center;">Compliance Admin</th><th style="text-align:center;">Reader</th><th style="text-align:center;">Account Manager</th><th style="text-align:center;">QA Admin</th></tr></thead><tbody><tr><td>Dashboard, Tenant Insights</td><td style="text-align:center;">Y</td><td style="text-align:center;">Y</td><td style="text-align:center;">Y</td><td style="text-align:center;">R</td><td style="text-align:center;">R</td><td style="text-align:center;">Y (scoped customers)</td><td style="text-align:center;">Y (scoped customers)</td></tr><tr><td>Customers (list, detail)</td><td style="text-align:center;">Y</td><td style="text-align:center;">Y</td><td style="text-align:center;">—</td><td style="text-align:center;">—</td><td style="text-align:center;">R</td><td style="text-align:center;">Y (scoped)</td><td style="text-align:center;">Y (scoped)</td></tr><tr><td>Tenants (list, detail)</td><td style="text-align:center;">Y</td><td style="text-align:center;">Y</td><td style="text-align:center;">—</td><td style="text-align:center;">—</td><td style="text-align:center;">R</td><td style="text-align:center;">Y (scoped)</td><td style="text-align:center;">Y (scoped)</td></tr><tr><td>Instances</td><td style="text-align:center;">Y</td><td style="text-align:center;">Y</td><td style="text-align:center;">—</td><td style="text-align:center;">—</td><td style="text-align:center;">R</td><td style="text-align:center;">—</td><td style="text-align:center;">Y (scoped instances)</td></tr><tr><td>Releases, Changelog, Environment</td><td style="text-align:center;">Y</td><td style="text-align:center;">Y</td><td style="text-align:center;">—</td><td style="text-align:center;">—</td><td style="text-align:center;">R</td><td style="text-align:center;">—</td><td style="text-align:center;">—</td></tr><tr><td>Migrations (list)</td><td style="text-align:center;">Y</td><td style="text-align:center;">Y</td><td style="text-align:center;">—</td><td style="text-align:center;">—</td><td style="text-align:center;">R</td><td style="text-align:center;">—</td><td style="text-align:center;">Y (scoped)</td></tr><tr><td>Migrations (start / rerun / rollback)</td><td style="text-align:center;">Y</td><td style="text-align:center;">Y</td><td style="text-align:center;">—</td><td style="text-align:center;">—</td><td style="text-align:center;">—</td><td style="text-align:center;">—</td><td style="text-align:center;">Y (scoped)</td></tr><tr><td>Internal Users (list)</td><td style="text-align:center;">Y</td><td style="text-align:center;">R</td><td style="text-align:center;">R</td><td style="text-align:center;">R</td><td style="text-align:center;">R</td><td style="text-align:center;">—</td><td style="text-align:center;">—</td></tr><tr><td>Internal User Invite / Edit</td><td style="text-align:center;">Y</td><td style="text-align:center;">—</td><td style="text-align:center;">—</td><td style="text-align:center;">—</td><td style="text-align:center;">—</td><td style="text-align:center;">—</td><td style="text-align:center;">—</td></tr><tr><td>System Workers, Discrepancies (list)</td><td style="text-align:center;">Y</td><td style="text-align:center;">Y</td><td style="text-align:center;">—</td><td style="text-align:center;">R</td><td style="text-align:center;">R</td><td style="text-align:center;">—</td><td style="text-align:center;">—</td></tr><tr><td>Discrepancies (purge / discard)</td><td style="text-align:center;">Y</td><td style="text-align:center;">Y</td><td style="text-align:center;">—</td><td style="text-align:center;">—</td><td style="text-align:center;">—</td><td style="text-align:center;">—</td><td style="text-align:center;">—</td></tr><tr><td>Audit Log, Email Logs</td><td style="text-align:center;">Y</td><td style="text-align:center;">Y</td><td style="text-align:center;">Y</td><td style="text-align:center;">R</td><td style="text-align:center;">R</td><td style="text-align:center;">—</td><td style="text-align:center;">—</td></tr><tr><td>User Attributes (definitions)</td><td style="text-align:center;">Y</td><td style="text-align:center;">—</td><td style="text-align:center;">—</td><td style="text-align:center;">—</td><td style="text-align:center;">—</td><td style="text-align:center;">—</td><td style="text-align:center;">—</td></tr><tr><td>Billing, Invoices, Payments</td><td style="text-align:center;">Y</td><td style="text-align:center;">—</td><td style="text-align:center;">Y</td><td style="text-align:center;">—</td><td style="text-align:center;">—</td><td style="text-align:center;">Y (scoped)</td><td style="text-align:center;">—</td></tr><tr><td>Plans, Meters, Usage Aggregates</td><td style="text-align:center;">Y</td><td style="text-align:center;">—</td><td style="text-align:center;">Y</td><td style="text-align:center;">—</td><td style="text-align:center;">—</td><td style="text-align:center;">—</td><td style="text-align:center;">—</td></tr><tr><td>Custom Plans, Credit Management</td><td style="text-align:center;">Y</td><td style="text-align:center;">—</td><td style="text-align:center;">Y</td><td style="text-align:center;">—</td><td style="text-align:center;">—</td><td style="text-align:center;">—</td><td style="text-align:center;">—</td></tr><tr><td>Billed-amount visibility (in $ figures)</td><td style="text-align:center;">Y</td><td style="text-align:center;">—</td><td style="text-align:center;">Y</td><td style="text-align:center;">R</td><td style="text-align:center;">R</td><td style="text-align:center;">R</td><td style="text-align:center;">—</td></tr></tbody></table><p>Each role gets a tailored sidebar — for example, Finance Admin sees a finance-only sidebar, and Compliance Admin sees an audit-focused sidebar. Reader sees the full operations sidebar minus Finance and admin-only items.</p><hr><h2 id="portal-roles" tabindex="-1">Portal roles <a class="header-anchor" href="#portal-roles" aria-label="Permalink to &quot;Portal roles&quot;">​</a></h2><p>Portal roles control what a customer&#39;s users can do inside their own customer&#39;s portal. Every user who can sign in to the portal holds exactly one portal role; a user with the <code>member</code> role has no portal access at all (only their own profile).</p><table tabindex="0"><thead><tr><th>Role</th><th>Code</th><th>Description</th></tr></thead><tbody><tr><td><strong>Owner</strong></td><td><code>owner</code></td><td>Full control. <strong>Exactly one per customer.</strong> Manages admins, transfers ownership, and is the only role that can delete the account.</td></tr><tr><td><strong>Admin</strong></td><td><code>admin</code></td><td>Manages users, tenants, settings, auth config, webhooks, and service accounts. Cannot promote anyone to Admin or Owner.</td></tr><tr><td><strong>Billing</strong></td><td><code>billing</code></td><td>Sees the dashboard, tenants, and instances; manages billing and invoices.</td></tr><tr><td><strong>Viewer</strong></td><td><code>viewer</code></td><td>Read-only access to dashboard, tenants, and instances.</td></tr><tr><td><strong>Member</strong></td><td><code>member</code></td><td>No portal access. Can only manage their own profile and MFA. Auto-assigned when a user is added to a tenant without an existing portal role.</td></tr></tbody></table><h3 id="portal-permission-matrix" tabindex="-1">Portal permission matrix <a class="header-anchor" href="#portal-permission-matrix" aria-label="Permalink to &quot;Portal permission matrix&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Capability</th><th style="text-align:center;">Owner</th><th style="text-align:center;">Admin</th><th style="text-align:center;">Billing</th><th style="text-align:center;">Viewer</th><th style="text-align:center;">Member</th></tr></thead><tbody><tr><td>Portal Dashboard</td><td style="text-align:center;">Y</td><td style="text-align:center;">Y</td><td style="text-align:center;">Y</td><td style="text-align:center;">Y</td><td style="text-align:center;">—</td></tr><tr><td>View Tenants &amp; Instances</td><td style="text-align:center;">Y</td><td style="text-align:center;">Y</td><td style="text-align:center;">Y</td><td style="text-align:center;">Y</td><td style="text-align:center;">—</td></tr><tr><td>View Users</td><td style="text-align:center;">Y</td><td style="text-align:center;">Y</td><td style="text-align:center;">—</td><td style="text-align:center;">—</td><td style="text-align:center;">—</td></tr><tr><td>Manage Users (invite, suspend, reactivate)</td><td style="text-align:center;">Y</td><td style="text-align:center;">Y</td><td style="text-align:center;">—</td><td style="text-align:center;">—</td><td style="text-align:center;">—</td></tr><tr><td>Manage Tenant Users (assign / remove)</td><td style="text-align:center;">Y</td><td style="text-align:center;">Y</td><td style="text-align:center;">—</td><td style="text-align:center;">—</td><td style="text-align:center;">—</td></tr><tr><td>View Billing &amp; Invoices</td><td style="text-align:center;">Y</td><td style="text-align:center;">Y</td><td style="text-align:center;">Y</td><td style="text-align:center;">—</td><td style="text-align:center;">—</td></tr><tr><td>Manage Billing</td><td style="text-align:center;">Y</td><td style="text-align:center;">Y</td><td style="text-align:center;">Y</td><td style="text-align:center;">—</td><td style="text-align:center;">—</td></tr><tr><td>Customer Settings</td><td style="text-align:center;">Y</td><td style="text-align:center;">Y</td><td style="text-align:center;">—</td><td style="text-align:center;">—</td><td style="text-align:center;">—</td></tr><tr><td>Auth Config (SSO, IdPs)</td><td style="text-align:center;">Y</td><td style="text-align:center;">Y</td><td style="text-align:center;">—</td><td style="text-align:center;">—</td><td style="text-align:center;">—</td></tr><tr><td>Service Accounts</td><td style="text-align:center;">Y</td><td style="text-align:center;">Y</td><td style="text-align:center;">—</td><td style="text-align:center;">—</td><td style="text-align:center;">—</td></tr><tr><td>Webhooks</td><td style="text-align:center;">Y</td><td style="text-align:center;">Y</td><td style="text-align:center;">—</td><td style="text-align:center;">—</td><td style="text-align:center;">—</td></tr><tr><td>Account Settings (own profile, MFA)</td><td style="text-align:center;">Y</td><td style="text-align:center;">Y</td><td style="text-align:center;">Y</td><td style="text-align:center;">Y</td><td style="text-align:center;">Y</td></tr><tr><td>Changelog</td><td style="text-align:center;">Y</td><td style="text-align:center;">Y</td><td style="text-align:center;">Y</td><td style="text-align:center;">Y</td><td style="text-align:center;">—</td></tr></tbody></table><h3 id="role-assignment" tabindex="-1">Role assignment <a class="header-anchor" href="#role-assignment" aria-label="Permalink to &quot;Role assignment&quot;">​</a></h3><p>Who can grant which portal role:</p><table tabindex="0"><thead><tr><th>Actor</th><th>Can assign</th><th>Cannot assign</th></tr></thead><tbody><tr><td><strong>Owner</strong></td><td><code>admin</code>, <code>billing</code>, <code>viewer</code>, <code>member</code></td><td><code>owner</code> (use <em>transfer</em>)</td></tr><tr><td><strong>Admin</strong></td><td><code>billing</code>, <code>viewer</code>, <code>member</code></td><td><code>owner</code>, <code>admin</code></td></tr></tbody></table><ul><li>Only the Owner can promote or demote Admins.</li><li>Admins cannot modify other Admins or the Owner.</li><li>Ownership transfer is a dedicated action — there is always exactly one Owner per customer, and the previous Owner is automatically demoted to Admin when ownership transfers.</li></ul><h3 id="owner-only-actions" tabindex="-1">Owner-only actions <a class="header-anchor" href="#owner-only-actions" aria-label="Permalink to &quot;Owner-only actions&quot;">​</a></h3><p>These actions are reserved exclusively for the Owner:</p><table tabindex="0"><thead><tr><th>Action</th><th>Detail</th></tr></thead><tbody><tr><td>Transfer ownership</td><td>Designate another portal user as the new Owner. The current Owner is demoted to Admin. Atomic.</td></tr><tr><td>Promote to Admin</td><td>Only the Owner can set a user&#39;s portal role to Admin.</td></tr><tr><td>Demote an Admin</td><td>Only the Owner can change an Admin&#39;s role to Billing, Viewer, or Member.</td></tr><tr><td>Delete customer account</td><td>Soft-delete the customer organisation. Requires a confirmation flow.</td></tr></tbody></table><p>The system blocks removing the Owner without first transferring ownership, and blocks self-demotion if you are the only Owner.</p><h3 id="member-behaviour" tabindex="-1">Member behaviour <a class="header-anchor" href="#member-behaviour" aria-label="Permalink to &quot;Member behaviour&quot;">​</a></h3><p>The Member role is a deliberate &quot;tenant-only&quot; state — the user exists to be a tenant user, not to manage anything at the customer level:</p><ul><li>All portal routes return HTTP 403.</li><li>A restricted layout (no sidebar) is shown.</li><li>After sign-in, the user is redirected straight to <strong>Account</strong>.</li><li>Auto-assigned when a user is added to a tenant without already having a portal role.</li></ul><hr><h2 id="tenant-roles" tabindex="-1">Tenant roles <a class="header-anchor" href="#tenant-roles" aria-label="Permalink to &quot;Tenant roles&quot;">​</a></h2><p>A user&#39;s <em>portal</em> role decides what they can do in the customer portal. Their <em>tenant</em> role decides what they can do <strong>inside a specific tenant</strong>. These are assigned independently — a Customer Admin might only be a Tenant User on one of the tenants, and vice versa.</p><table tabindex="0"><thead><tr><th>Role</th><th>Code</th><th>Description</th></tr></thead><tbody><tr><td><strong>Tenant Admin</strong></td><td><code>tenant_admin</code></td><td>Admin within the tenant. Enforced by the Exto instance, not by the Console.</td></tr><tr><td><strong>Tenant User</strong></td><td><code>tenant_user</code></td><td>Regular user within the tenant.</td></tr></tbody></table><p>Tenant roles are passed to the instance during user provisioning. The instance — not the Console — enforces what each tenant role can do once the user is signed in to that tenant.</p><hr><h2 id="portal-actions" tabindex="-1">Portal actions <a class="header-anchor" href="#portal-actions" aria-label="Permalink to &quot;Portal actions&quot;">​</a></h2><p>Underneath portal roles, individual pages and buttons are gated by <strong>portal actions</strong> such as <code>view_dashboard</code>, <code>view_users</code>, <code>manage_users</code>, <code>view_billing</code>, <code>manage_billing</code>, <code>manage_settings</code>. When the UI hides a button or page, the missing action is the reason.</p><p>The portal role → portal action mapping is what the permission matrix above describes.</p><hr><h2 id="account-manager-scope" tabindex="-1">Account Manager scope <a class="header-anchor" href="#account-manager-scope" aria-label="Permalink to &quot;Account Manager scope&quot;">​</a></h2><p>Account Managers see only the customers in their scope. If an AM has scope <code>{Acme, Globex}</code>, they cannot list, open, or operate on any other customer — those rows simply do not appear. This is <strong>scope hiding</strong>, not just access denial: the AM never sees data outside their scope.</p><h2 id="qa-admin-scope" tabindex="-1">QA Admin scope <a class="header-anchor" href="#qa-admin-scope" aria-label="Permalink to &quot;QA Admin scope&quot;">​</a></h2><p>QA Admins are doubly scoped:</p><ul><li>The <strong>customer scope</strong> decides which customers they may operate on.</li><li>The <strong>instance scope</strong> decides which instances they may act against.</li></ul><p>QA Admins are typically used to run validation flows against specific non-prod customers and instances without granting broad access.</p><h2 id="notifications" tabindex="-1">Notifications <a class="header-anchor" href="#notifications" aria-label="Permalink to &quot;Notifications&quot;">​</a></h2><p>A separate layer of subscriptions controls what notifications users receive (in-app and email). Notifications are grouped by category — Operations, Discrepancies, Billing, Infrastructure, General. Some subscriptions are marked <strong>Required</strong> for the user&#39;s role and cannot be turned off.</p><p>Users manage their own subscriptions on the <strong>Account</strong> page. Operators viewing another user&#39;s detail page see subscriptions read-only.</p><h2 id="focus-mode" tabindex="-1">Focus mode <a class="header-anchor" href="#focus-mode" aria-label="Permalink to &quot;Focus mode&quot;">​</a></h2><p>Operators with broad access can enter <strong>focus mode</strong> on a single customer. While focused, the Dashboard and other aggregate views hide cross-customer information and present only the focused customer&#39;s data. Focus mode is a viewing convenience — it does not change what the operator is permitted to do.</p><hr><h2 id="source-of-truth" tabindex="-1">Source of truth <a class="header-anchor" href="#source-of-truth" aria-label="Permalink to &quot;Source of truth&quot;">​</a></h2><p>The backend is the source of truth for every check in these matrices. The Console UI uses the same mapping to hide buttons and filter the sidebar, but a request that bypasses the UI still gets a 403 from the server — there is no UI-only permission anywhere in Console.</p>',56)])])}const m=e(s,[["render",d]]);export{y as __pageData,m as default};
